import 'package:injectable/injectable.dart'; @injectable class BitrateController { int _targetKbps = 2000; static const _min = 300; static const _max = 8000; int get targetKbps => _targetKbps; void adaptToBandwidth(double estimatedKbps) { if (estimatedKbps < _targetKbps * 0.8) { _targetKbps = (_targetKbps * 0.75).clamp(_min, _max).round(); } else if (estimatedKbps > _targetKbps * 1.2) { _targetKbps = (_targetKbps * 1.1).clamp(_min, _max).round(); } } void reset() => _targetKbps = 2000; }